package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testToString() {
        // Given
        char delimiter = ',';
        char escapeCharacter = '\\';
        char quoteCharacter = '"';
        char commentMarker = '#';
        String recordSeparator = "\r\n";
        String nullString = "NULL";
        String[] header = {"Header1", "Header2"};
        boolean skipHeaderRecord = true;

        CSVFormat csvFormat = new CSVFormat(delimiter, quoteCharacter, null, commentMarker, escapeCharacter,
                false, true, recordSeparator, nullString, header, skipHeaderRecord, false);

        // When
        String result = csvFormat.toString();

        // Then
        String expected = "Delimiter=<,> Escape=<\\> QuoteChar=<\"> CommentStart=<#> RecordSeparator=<\r\n> SkipHeaderRecord:true Header:[Header1, Header2]";
        assertEquals(expected, result);
    }
}
